arguments.command:
system_profiler SPFontsDataType -json 2>/dev/null | python3 -c "
import json, sys
data = json.load(sys.stdin)
for font in data.get('SPFontsDataType', []):
    fname = font.get('_name', '')
    if 'Writer' in fname or 'iA' in fname:
        print(f'File: {font.get(\"path\",\"\").split(\"/\")[-1]}')
        for k, v in sorted(font.items()):
            if k != '_name' and k != 'path':
                print(f'  {k}: {v}')
        print()
"

